import{_ as s,o as a,c as r,ag as e}from"./chunks/framework.D9bIGSBm.js";const p=JSON.parse('{"title":"分享设置","description":"","frontmatter":{},"headers":[],"relativePath":"settings/share.md","filePath":"settings/share.md"}'),o={name:"settings/share.md"};function n(l,t,i,d,h,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="分享设置" tabindex="-1">分享设置 <a class="header-anchor" href="#分享设置" aria-label="Permalink to &quot;分享设置&quot;">​</a></h1><p><strong>入口：</strong> 设置 → <strong>分享</strong></p><p>配置<a href="/docs/features/session-share.html">会话分享</a>所使用的分享服务器（v0.9.8 起）。<strong>绝大多数用户无需任何配置</strong>——两项留空即使用 LoongCode 官方分享服务，开箱即用；仅当团队自行部署了分享服务器（例如出于内网合规需要）时才需要填写。</p><hr><h2 id="配置项" tabindex="-1">配置项 <a class="header-anchor" href="#配置项" aria-label="Permalink to &quot;配置项&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>服务器地址</strong></td><td><strong>留空</strong>即使用官方分享服务器；自部署时填写你的分享服务根地址（<code>https://</code> 开头）</td></tr><tr><td><strong>访问密钥</strong></td><td><strong>留空</strong>即使用内置密钥（配合官方服务）；自部署时填写与你的服务器端一致的访问密钥</td></tr></tbody></table><p>修改后点击<strong>保存</strong>生效。</p><div class="tip custom-block"><p class="custom-block-title">密钥的作用</p><p>访问密钥用于对创建 / 撤销分享的请求做签名校验，防止分享服务被无关客户端滥用；它不加密分享内容本身。分享页的访问控制依靠链接中的随机段与有效期；v0.9.10 起还支持可选的<strong>密码保护</strong>（创建时由客户端生成随机密码附在链接中，服务器先验密码再返回内容），详见<a href="/docs/features/session-share.html#隐私与安全">会话分享 → 隐私与安全</a>。</p></div><div class="warning custom-block"><p class="custom-block-title">自部署注意</p><ul><li>服务器地址与访问密钥必须与你部署的分享服务端配置匹配，密钥不一致时创建分享会提示「访问密钥无效，请检查设置」。</li><li>更换服务器地址只影响<strong>之后</strong>的操作；此前在旧服务器上创建的分享链接仍托管在旧服务器上。若需让旧链接提前失效，请在<strong>切换配置前</strong>先完成撤销，或等待其自然过期。</li></ul></div><hr><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/docs/features/session-share.html">会话分享</a> — 创建、查看与撤销分享的完整用法</li></ul>',12)])])}const u=s(o,[["render",n]]);export{p as __pageData,u as default};
